import React from "react";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  { title: "Certified SAFe® 6 PO/PdM", company: "Scaled Agile", date: "2024", icon: <FaUniversity /> },
  { title: "Senior Product Manager", company: "EY", date: "2022-Present", icon: <FaBriefcase /> },
  { title: "Certified Scrum PO (CSPO)", company: "Scrum Alliance", date: "2022", icon: <FaUniversity /> },
  { title: "Senior Product Manager", company: "J.P. Morgan", date: "2021-2022", icon: <FaBriefcase /> },
  { title: "Azure Fundamentals", company: "Azure", date: "2021", icon: <FaCloud /> },
  { title: "PMI Agile Certified Practitioner", company: "PMI", date: "2019", icon: <FaUniversity /> },
  { title: "Senior Product Manager", company: "ExxonMobil", date: "2014-2021", icon: <FaBriefcase /> },
  { title: "Senior Product Owner", company: "ExxonMobil", date: "2013-2014", icon: <FaBriefcase /> },
  { title: "Senior Scrum Master", company: "ExxonMobil", date: "2008-2013", icon: <FaBriefcase /> },
  { title: "Supervisor", company: "IBM", date: "2001-2008", icon: <FaBriefcase /> },
  { title: "Master of Systems Engineering", company: "Universidad Tecnologica Nacional (UTN)", date: "2001-2006", icon: <FaUniversity /> }
];

const ExperienceTimeline = () => {
  return (
    <div className="overflow-x-auto py-10">
      <div className="flex relative items-center justify-start min-w-[1500px]">
        {/* Línea horizontal */}
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-300 z-0" />

        {experienceData.map((item, index) => {
          const isWork = item.icon.type === FaBriefcase;
          const boxPosition = isWork ? "top-[-6rem]" : "top-[6rem]";
          const textAlign = isWork ? "items-end" : "items-start";
          const boxColor = isWork
            ? "bg-gradient-to-r from-black via-gray-800 to-white text-white"
            : "bg-gradient-to-r from-blue-600 via-blue-300 to-white text-black";

          return (
            <div key={index} className="relative flex flex-col items-center w-44 mx-4 z-10">
              {/* Caja de experiencia */}
              <div className={`absolute ${boxPosition} w-44 flex ${textAlign}`}>
                <div className={`rounded-lg shadow-lg px-3 py-2 w-full ${boxColor}`}>
                  <p className="text-xs italic">{item.date}</p>
                  <p className="font-semibold text-sm">{item.title}</p>
                  <p className="text-xs">{item.company}</p>
                </div>
              </div>

              {/* Icono */}
              <div className="w-10 h-10 flex items-center justify-center bg-white rounded-full border-2 border-gray-400 z-10">
                {item.icon}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default ExperienceTimeline;
